// LESS format — define @variables here as needed
// Generated by sumd for vscode-doql

app {
  name: vscode-doql;
  version: 0.2.0;
}

interface[type="web"] {
  framework: typescript;
}

workflow[name="install"] {
  trigger: manual;
  step-1: run cmd=npm install;
}

workflow[name="dev"] {
  trigger: manual;
  step-1: run cmd=npm run dev;
}

workflow[name="build"] {
  trigger: manual;
  step-1: run cmd=npm run build;
}

workflow[name="test"] {
  trigger: manual;
  step-1: run cmd=npm test;
}

workflow[name="lint"] {
  trigger: manual;
  step-1: run cmd=npm run lint;
}

workflow[name="fmt"] {
  trigger: manual;
  step-1: run cmd=npm run format;
}

workflow[name="clean"] {
  trigger: manual;
  step-1: run cmd=rm -rf node_modules dist build .cache;
}

workflow[name="vscode:prepublish"] {
  trigger: manual;
  step-1: run cmd=npm run vscode:prepublish;
}

workflow[name="compile"] {
  trigger: manual;
  step-1: run cmd=npm run compile;
}

workflow[name="watch"] {
  trigger: manual;
  step-1: run cmd=npm run watch;
}

workflow[name="help"] {
  trigger: manual;
  step-1: run cmd=task --list;
}

deploy {
  target: npm;
}

environment[name="local"] {
  runtime: node;
}
```
